import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ResumeTemplate } from '../../../core/models/resume.model';
import { ResumeBuilderLocalService } from '../../../core/services/resume-builder-local.service';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-resume-form',
  templateUrl: './resume-form.component.html'
})
export class ResumeFormComponent implements OnInit {
  template: ResumeTemplate | null = null;
  activeTab: 'overview' | 'content' | 'customize' | 'ai' = 'content';
  loading = true;
  submitting = false;
  error = '';

  readonly form = this.formBuilder.group({
    title: ['My ATS Resume', Validators.required],
    fullName: ['', Validators.required],
    headline: ['Entry-level candidate focused on ATS-friendly recruiter screening'],
    email: ['', [Validators.required, Validators.email]],
    phone: ['', Validators.required],
    links: ['LinkedIn | GitHub'],
    education: this.formBuilder.array([this.createLineControl('B.Tech / Degree, Institute, Graduation Year')]),
    skills: this.formBuilder.array([this.createLineControl('Java, Spring Boot, MySQL, Angular')]),
    projects: this.formBuilder.array([this.createLineControl('Project title - outcome, stack, measurable impact')]),
    experience: this.formBuilder.array([this.createLineControl('Internship / training / volunteer work with outcomes')]),
    certifications: this.formBuilder.array([this.createLineControl('Certification name - platform / issuer')]),
    achievements: this.formBuilder.array([this.createLineControl('Achievement or competition result')]),
    languages: this.formBuilder.array([this.createLineControl('English')]),
    designFont: ['Source Sans Pro'],
    designAccent: ['#59707c'],
    designText: ['#111827'],
    pageFormat: ['A4']
  });

  readonly fontOptions = ['Source Sans Pro', 'Karla', 'Mulish', 'Lato', 'Roboto', 'Work Sans'];
  readonly accentOptions = ['#59707c', '#2563eb', '#7c3aed', '#0f766e', '#b45309', '#1f2937'];

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly route: ActivatedRoute,
    private readonly router: Router,
    private readonly resumeBuilderLocalService: ResumeBuilderLocalService,
    private readonly resumeService: ResumeService
  ) {
  }

  ngOnInit(): void {
    const templateId = Number(this.route.snapshot.paramMap.get('templateId'));
    this.resumeService.getTemplateDetail(templateId).subscribe({
      next: (template) => {
        this.template = template;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }

  get education(): FormArray {
    return this.form.get('education') as FormArray;
  }

  get skills(): FormArray {
    return this.form.get('skills') as FormArray;
  }

  get projects(): FormArray {
    return this.form.get('projects') as FormArray;
  }

  get experience(): FormArray {
    return this.form.get('experience') as FormArray;
  }

  get certifications(): FormArray {
    return this.form.get('certifications') as FormArray;
  }

  get achievements(): FormArray {
    return this.form.get('achievements') as FormArray;
  }

  get languages(): FormArray {
    return this.form.get('languages') as FormArray;
  }

  get previewHtml(): string {
    if (!this.template) {
      return '';
    }
    return this.resumeBuilderLocalService.buildPreviewHtml(
      this.template,
      (this.form.value.title as string) || 'My ATS Resume',
      this.form.getRawValue() as Record<string, unknown>
    );
  }

  addItem(array: FormArray, placeholder = ''): void {
    array.push(this.createLineControl(placeholder));
  }

  removeItem(array: FormArray, index: number): void {
    if (array.length > 1) {
      array.removeAt(index);
    }
  }

  submit(): void {
    if (this.form.invalid || !this.template) {
      this.form.markAllAsTouched();
      return;
    }

    this.submitting = true;
    this.error = '';

    try {
      const resume = this.resumeBuilderLocalService.createResume(
        this.template,
        this.form.value.title as string,
        this.form.getRawValue() as Record<string, unknown>
      );
      this.router.navigate(['/resume-builder/preview', resume.id]);
    } catch (error) {
      this.submitting = false;
      this.error = error instanceof Error ? error.message : 'Failed to generate resume.';
    }
  }

  private createLineControl(initialValue = ''): FormGroup {
    return this.formBuilder.group({
      value: [initialValue, Validators.required]
    });
  }
}
<app-loader *ngIf="loading" message="Preparing resume builder"></app-loader>

<div *ngIf="!loading && template" class="space-y-6">
  <div class="glass-panel p-6">
    <p class="text-sm font-semibold uppercase tracking-[0.28em] text-poppy">Template Selected</p>
    <h2 class="section-title mt-2 text-4xl">{{ template.name }}</h2>
    <p class="mt-4 max-w-3xl text-base leading-7 text-ink/65">
      Prioritize projects, skills, education, internships, certifications, and recruiter-facing links. Keep every bullet outcome-focused.
    </p>
  </div>

  <form class="space-y-6" [formGroup]="form" (ngSubmit)="submit()">
    <section class="glass-panel p-6">
      <h3 class="section-title text-3xl">Personal details</h3>
      <div class="mt-5 grid gap-4 md:grid-cols-2">
        <input class="field" formControlName="title" placeholder="Resume title">
        <input class="field" formControlName="fullName" placeholder="Full name">
        <input class="field" formControlName="headline" placeholder="Headline / summary line">
        <input class="field" formControlName="email" placeholder="Email">
        <input class="field" formControlName="phone" placeholder="Phone">
        <input class="field" formControlName="links" placeholder="GitHub / LinkedIn / Portfolio">
      </div>
    </section>

    <section class="glass-panel p-6">
      <h3 class="section-title text-3xl">Core sections</h3>
      <div class="mt-6 grid gap-6 lg:grid-cols-2">
        <div>
          <p class="mb-3 font-semibold text-ink">Education</p>
          <div formArrayName="education" class="space-y-3">
            <div *ngFor="let group of education.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Education entry">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(education, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(education)">Add Education</button>
        </div>

        <div>
          <p class="mb-3 font-semibold text-ink">Skills</p>
          <div formArrayName="skills" class="space-y-3">
            <div *ngFor="let group of skills.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Skill entry">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(skills, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(skills)">Add Skill</button>
        </div>

        <div>
          <p class="mb-3 font-semibold text-ink">Projects</p>
          <div formArrayName="projects" class="space-y-3">
            <div *ngFor="let group of projects.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Project bullet">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(projects, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(projects)">Add Project</button>
        </div>

        <div>
          <p class="mb-3 font-semibold text-ink">Experience / Internship</p>
          <div formArrayName="experience" class="space-y-3">
            <div *ngFor="let group of experience.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Experience bullet">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(experience, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(experience)">Add Experience</button>
        </div>
      </div>
    </section>

    <section class="glass-panel p-6">
      <h3 class="section-title text-3xl">Supporting sections</h3>
      <div class="mt-6 grid gap-6 lg:grid-cols-3">
        <div>
          <p class="mb-3 font-semibold text-ink">Certifications</p>
          <div formArrayName="certifications" class="space-y-3">
            <div *ngFor="let group of certifications.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Certification">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(certifications, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(certifications)">Add Certification</button>
        </div>

        <div>
          <p class="mb-3 font-semibold text-ink">Achievements</p>
          <div formArrayName="achievements" class="space-y-3">
            <div *ngFor="let group of achievements.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Achievement">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(achievements, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(achievements)">Add Achievement</button>
        </div>

        <div>
          <p class="mb-3 font-semibold text-ink">Languages</p>
          <div formArrayName="languages" class="space-y-3">
            <div *ngFor="let group of languages.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Language">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(languages, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(languages)">Add Language</button>
        </div>
      </div>
    </section>

    <p *ngIf="error" class="rounded-2xl bg-poppy/10 px-4 py-3 text-sm font-medium text-poppy">{{ error }}</p>

    <div class="flex gap-3">
      <button class="btn-primary" type="submit" [disabled]="submitting">{{ submitting ? 'Generating...' : 'Generate Resume' }}</button>
      <a routerLink="/resume-builder/templates" class="btn-secondary">Back to Templates</a>
    </div>
  </form>
</div>
